"use strict";document.body.insertAdjacentHTML("beforeend",'<div style="display:flex;height:100vh;overflow:hidden;">\x3c!-- ══════════════ LEFT SIDEBAR ══════════════ --\x3e<aside class="sidebar" style="width:252px;min-width:252px;overflow-y:auto;display:flex;flex-direction:column;padding:0 0 .75rem">\x3c!-- Branding --\x3e<div style="padding:.875rem .875rem .6rem;border-bottom:1px solid rgba(74,126,196,.15)"><div style="display:flex;align-items:center;gap:.55rem;margin-bottom:.3rem"><div style="width:30px;height:30px;background:linear-gradient(135deg,#d4a017,#e8b420);border-radius:6px;display:flex;align-items:center;justify-content:center;font-weight:900;font-size:.8rem;color:#0f2744;flex-shrink:0">I</div><div><div style="font-weight:700;font-size:.85rem;color:#e2e8f0">ILAW Generator</div><div style="font-size:.58rem;color:#64748b;letter-spacing:.05em">DO No. 016, s. 2026 · DepEd PH</div></div></div><div style="display:flex;align-items:center;gap:.35rem;margin-top:.25rem"><span style="width:6px;height:6px;border-radius:50%;background:#22c55e;box-shadow:0 0 0 2px rgba(34,197,94,.2);flex-shrink:0"></span><span style="font-size:.6rem;color:#64748b" id="pwa-lbl">Offline Ready</span><span style="margin-left:auto;display:flex;align-items:center;gap:.3rem"><span id="save-dot" style="width:6px;height:6px;border-radius:50%;background:#22c55e;flex-shrink:0"></span><span style="font-size:.6rem;color:#64748b" id="save-lbl">Saved</span></span></div></div>\x3c!-- Tabs --\x3e<div style="display:flex;padding:.4rem .5rem .2rem;gap:.2rem;border-bottom:1px solid rgba(74,126,196,.12)"><button class="tab-btn active" onclick="switchTab(\'plan\')" id="tab-plan">Plan</button><button class="tab-btn" onclick="switchTab(\'calc\')" id="tab-calc">Grades</button><button class="tab-btn" onclick="switchTab(\'about\')" id="tab-about">Help</button></div>\x3c!-- ── TAB: PLAN ── --\x3e<div id="panel-plan" class="tab-panel active" style="padding:.7rem .875rem 0;flex:1;display:flex;flex-direction:column"><span class="lbl">Teacher Info</span><div style="display:flex;flex-direction:column;gap:.35rem;margin-bottom:.6rem"><input class="ctrl" id="t-name" type="text" placeholder="Full name"/><input class="ctrl" id="t-school" type="text" placeholder="School name"/><div style="display:grid;grid-template-columns:1fr 1fr;gap:.35rem"><input class="ctrl" id="t-section" type="text" placeholder="Section"/><input class="ctrl" id="t-date" type="date"/></div><div style="display:grid;grid-template-columns:1fr 1fr;gap:.35rem"><input class="ctrl" id="t-time" type="time" value="07:30"/><input class="ctrl" id="t-dur" type="text" placeholder="60 mins" value="60 mins"/></div></div><div class="divider"></div><span class="lbl">Curriculum</span><div style="display:flex;flex-direction:column;gap:.35rem;margin-bottom:.5rem"><select class="ctrl" id="sel-grade"><option value="">— Grade Level —</option><optgroup label="Key Stage 1"><option value="1">Grade 1</option><option value="2">Grade 2</option><option value="3">Grade 3</option></optgroup><optgroup label="Key Stage 2"><option value="4">Grade 4</option><option value="5">Grade 5</option><option value="6">Grade 6</option></optgroup><optgroup label="Key Stage 3"><option value="7">Grade 7</option><option value="8">Grade 8</option><option value="9">Grade 9</option><option value="10">Grade 10</option></optgroup><optgroup label="Key Stage 4 (SHS)"><option value="11">Grade 11</option><option value="12">Grade 12</option></optgroup></select><div id="ks-wrap" style="display:none"><span class="ksbadge" id="ks-badge"></span></div><select class="ctrl" id="sel-subject"><option value="">— Subject —</option></select><div style="display:grid;grid-template-columns:1fr 1fr;gap:.35rem"><select class="ctrl" id="sel-q"><option value="">— Q —</option><option value="1">Q1</option><option value="2">Q2</option><option value="3">Q3</option><option value="4">Q4</option></select><select class="ctrl" id="sel-week"><option value="">— Wk —</option></select></div><input class="ctrl" id="t-melc" type="text" placeholder="Custom competency (optional)" style="font-size:.72rem"/></div><div class="divider"></div><span class="lbl">Adaptive Context</span><div style="margin-bottom:.5rem"><div class="trow"><input type="checkbox" id="tog-diverse"/><label for="tog-diverse">Diverse Learner Accommodations</label></div><div class="trow"><input type="checkbox" id="tog-lr"/><label for="tog-lr">Low-Resource Environment</label></div><div class="trow"><input type="checkbox" id="tog-values"/><label for="tog-values">Values Integration (Spiritual / Civic)</label></div><div style="margin-top:.35rem"><select class="ctrl" id="sel-tier"><option value="normal">🟢 Normal — Regular Classroom</option><option value="hinay">🔵 Hinay — Ease-In (Hybrid)</option><option value="hinga">🟡 Hinga — Check-In (Home-Based)</option><option value="hinto">🔴 Hinto — Stop (PFA Mode)</option></select></div></div><div class="divider"></div><span class="lbl">AI Declaration <span style="font-weight:400;color:#64748b;font-size:.6rem">(DO 003, s. 2026)</span></span><div style="margin-bottom:.5rem"><div class="trow"><input type="checkbox" id="ai-g"/><label for="ai-g">Grammar &amp; spelling</label></div><div class="trow"><input type="checkbox" id="ai-f"/><label for="ai-f">Formatting</label></div><div class="trow"><input type="checkbox" id="ai-s"/><label for="ai-s">Idea scaffolding</label></div><div class="trow"><input type="checkbox" id="ai-t"/><label for="ai-t">Translation (Fil ↔ Eng)</label></div></div>\x3c!-- AI Generate button --\x3e<div style="margin-top:auto"><div class="ai-thinking" id="ai-status"><span class="pulse">✦</span><span id="ai-msg">Claude is writing your lesson plan…</span></div><button id="ai-gen-btn" class="abtn bai" style="width:calc(100% - .1rem);margin-bottom:.35rem" onclick="generateWithAI()"><svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><path d="M12 2l3.09 6.26L22 9.27l-5 4.87 1.18 6.88L12 17.77l-6.18 3.25L7 14.14 2 9.27l6.91-1.01z"/></svg>\n Generate with AI (Claude)\n </button><button id="gen-btn" onclick="generateTemplate()"><svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><rect x="3" y="3" width="18" height="18" rx="2"/><path d="M3 9h18M9 21V9"/></svg>\n Use Template\n </button></div></div>\x3c!-- ── TAB: GRADES CALCULATOR ── --\x3e<div id="panel-calc" class="tab-panel" style="padding:.7rem .875rem"><span class="lbl">Class Record Calculator</span><div id="calc-ks1-note" style="display:none;background:rgba(22,101,52,.12);border:1px solid rgba(134,239,172,.3);border-radius:5px;padding:.5rem .7rem;font-size:.7rem;color:#86efac;margin-bottom:.6rem">\n Key Stage 1 (Grades 1–3): No numerical grading. Use qualitative PACE forms.\n </div><div id="calc-fields"><div style="margin-bottom:.5rem"><span class="lbl">Written Works (20%)</span><div style="display:grid;grid-template-columns:1fr 1fr;gap:.3rem;align-items:center"><input class="calc-input ctrl" id="ww-raw" type="number" placeholder="Raw" min="0" oninput="computeGrade()"/><input class="calc-input ctrl" id="ww-total" type="number" placeholder="/ Total" min="0" oninput="computeGrade()"/></div></div><div style="margin-bottom:.5rem"><span class="lbl">Performance Tasks (50%)</span><div style="display:grid;grid-template-columns:1fr 1fr;gap:.3rem"><input class="calc-input ctrl" id="pt-raw" type="number" placeholder="Raw" min="0" oninput="computeGrade()"/><input class="calc-input ctrl" id="pt-total" type="number" placeholder="/ Total" min="0" oninput="computeGrade()"/></div></div><div style="margin-bottom:.5rem"><span class="lbl">Summative Tests (30%)</span><div style="display:grid;grid-template-columns:1fr 1fr;gap:.3rem"><input class="calc-input ctrl" id="st-raw" type="number" placeholder="Raw" min="0" oninput="computeGrade()"/><input class="calc-input ctrl" id="st-total" type="number" placeholder="/ Total" min="0" oninput="computeGrade()"/></div></div><div class="grade-result" id="grade-result" style="display:none"><div style="font-size:.62rem;color:#64748b;letter-spacing:.08em;text-transform:uppercase;margin-bottom:.3rem">Transmuted Grade</div><div style="font-size:2rem;font-weight:800;color:#e2e8f0" id="grade-val">—</div><div style="font-size:.7rem;margin-top:.2rem" id="grade-status"></div><div style="margin-top:.5rem;font-size:.65rem;color:#64748b" id="grade-breakdown"></div></div></div></div>\x3c!-- ── TAB: HELP ── --\x3e<div id="panel-about" class="tab-panel" style="padding:.7rem .875rem"><span class="lbl">ILAW Framework</span><div style="background:rgba(74,126,196,.08);border-radius:7px;padding:.7rem;margin-bottom:.6rem"><div style="font-size:.72rem;color:#c7d7f0;line-height:1.7"><div><strong style="color:#e8b420">I</strong> — <strong>Intentions</strong>: CPA Objectives + MELC</div><div><strong style="color:#e8b420">L</strong> — <strong>Learning Experience</strong>: Pre-Lesson, The Flow, Steps</div><div><strong style="color:#e8b420">A</strong> — <strong>Assessing Learning</strong>: Tasks, Rubrics, Grading</div><div><strong style="color:#e8b420">W</strong> — <strong>Ways Forward</strong>: Remediation, Enrichment, Home</div></div></div><span class="lbl">Emergency Tiers</span><div style="font-size:.7rem;color:#94a3b8;line-height:1.65;margin-bottom:.6rem"><div>🟢 <strong style="color:#c7d7f0">Normal</strong> — Regular face-to-face</div><div>🔵 <strong style="color:#c7d7f0">Hinay</strong> — Hybrid with SLPs</div><div>🟡 <strong style="color:#c7d7f0">Hinga</strong> — Full home-based modular</div><div>🔴 <strong style="color:#c7d7f0">Hinto</strong> — Academic suspension + PFA</div></div><span class="lbl">Key Stage Grading</span><div style="font-size:.7rem;color:#94a3b8;line-height:1.65;margin-bottom:.6rem"><div>KS1 (G1–3): Qualitative PACE only — no exams</div><div>KS2–4 (G4–12): WW 20% + PT 50% + ST 30%</div><div>Passing: Raw ≥70% → Transmuted ≥75%</div></div><span class="lbl">AI Generation</span><div style="font-size:.7rem;color:#94a3b8;line-height:1.65">\n Click <strong style="color:#c4b5fd">Generate with AI</strong> for a fully custom plan written by Claude. Uses the Anthropic API — requires an internet connection for this feature only.\n </div><div style="margin-top:.7rem;font-size:.62rem;color:#475569">v2.0 · All data stored locally · No student data transmitted</div></div></aside>\x3c!-- ══════════════ CENTER CANVAS ══════════════ --\x3e<main style="flex:1;overflow:hidden;display:flex;flex-direction:column;background:#dde3ec"><div id="topbar" style="background:#fff;border-bottom:1px solid #e2e8f0;padding:.45rem .875rem;display:flex;align-items:center;gap:.6rem;flex-shrink:0"><div style="font-size:.73rem;font-weight:700;color:#1e3a5f">ILAW Lesson Plan</div><span id="doc-lbl" style="font-size:.67rem;color:#94a3b8">Select grade & subject, then generate</span><div style="margin-left:auto;font-size:.62rem;color:#94a3b8">DepEd ILAW Framework · DO 016-2026</div></div><div id="paper-wrap"><div id="paper"><div id="quill-editor"></div></div></div></main>\x3c!-- ══════════════ RIGHT SIDEBAR ══════════════ --\x3e<aside class="right-panel" style="width:188px;min-width:188px;padding:.875rem .75rem;display:flex;flex-direction:column;gap:.4rem;overflow-y:auto"><div class="lbl">Actions</div><button class="abtn bp" onclick="saveDraft()"><svg width="12" height="12" fill="none" stroke="currentColor" stroke-width="2.5" viewBox="0 0 24 24"><path d="M19 21H5a2 2 0 01-2-2V5a2 2 0 012-2h11l5 5v11a2 2 0 01-2 2z"/><polyline points="17,21 17,13 7,13 7,21"/><polyline points="7,3 7,8 15,8"/></svg>Save Draft</button><button class="abtn bg" onclick="exportDocx()"><svg width="12" height="12" fill="none" stroke="currentColor" stroke-width="2.5" viewBox="0 0 24 24"><path d="M14 2H6a2 2 0 00-2 2v16a2 2 0 002 2h12a2 2 0 002-2V8z"/><polyline points="14,2 14,8 20,8"/></svg>Export .docx</button><button class="abtn ba" onclick="exportPDF()"><svg width="12" height="12" fill="none" stroke="currentColor" stroke-width="2.5" viewBox="0 0 24 24"><path d="M14 2H6a2 2 0 00-2 2v16a2 2 0 002 2h12a2 2 0 002-2V8z"/><polyline points="14,2 14,8 20,8"/><line x1="16" y1="13" x2="8" y2="13"/><line x1="16" y1="17" x2="8" y2="17"/></svg>Export PDF</button><button class="abtn bgh" onclick="window.print()"><svg width="12" height="12" fill="none" stroke="currentColor" stroke-width="2.5" viewBox="0 0 24 24"><polyline points="6,9 6,2 18,2 18,9"/><path d="M6 18H4a2 2 0 01-2-2v-5a2 2 0 012-2h16a2 2 0 012 2v5a2 2 0 01-2 2h-2"/><rect x="6" y="14" width="12" height="8"/></svg>Print</button><div class="divider"></div><button class="abtn bgh" onclick="loadDraft()"><svg width="12" height="12" fill="none" stroke="currentColor" stroke-width="2.5" viewBox="0 0 24 24"><path d="M21 15v4a2 2 0 01-2 2H5a2 2 0 01-2-2v-4"/><polyline points="17,8 12,3 7,8"/><line x1="12" y1="3" x2="12" y2="15"/></svg>Load Draft</button><button class="abtn bgh" onclick="clearAll()"><svg width="12" height="12" fill="none" stroke="currentColor" stroke-width="2.5" viewBox="0 0 24 24"><polyline points="3,6 5,6 21,6"/><path d="M19 6l-1 14a2 2 0 01-2 2H8a2 2 0 01-2-2L5 6"/></svg>Clear</button><div class="divider"></div><div id="pwa-wrap" style="display:none"><button class="abtn bgh" id="pwa-btn"><svg width="12" height="12" fill="none" stroke="currentColor" stroke-width="2.5" viewBox="0 0 24 24"><path d="M21 16V8a2 2 0 00-1-1.73l-7-4a2 2 0 00-2 0l-7 4A2 2 0 003 8v8a2 2 0 001 1.73l7 4a2 2 0 002 0l7-4A2 2 0 0021 16z"/></svg>Install App</button></div><div style="margin-top:auto;background:rgba(74,126,196,.08);border:1px solid rgba(74,126,196,.18);border-radius:8px;padding:.65rem"><div class="lbl" style="margin-bottom:.35rem">Framework</div><div style="font-size:.67rem;color:#94a3b8;line-height:1.6"><div><strong style="color:#e8b420">I</strong> Intentions</div><div><strong style="color:#e8b420">L</strong> Learning Experience</div><div><strong style="color:#e8b420">A</strong> Assessing Learning</div><div><strong style="color:#e8b420">W</strong> Ways Forward</div></div><div style="margin-top:.45rem;font-size:.58rem;color:#475569">Data stays on your device</div></div></aside></div><div id="toast"></div><script>\n/* ═══════════════════════════════════════════════\n CURRICULUM DATABASE (multi-subject, all KS)\n═══════════════════════════════════════════════ */\nconst DB = {\n "1":{ks:1,subjects:["Science","Mathematics","Filipino","English","Araling Panlipunan","MAPEH","MTB-MLE"],data:{\n "Science":{"3":{"5":{code:"S1FE-IIIi-j-5",text:"Use senses to locate and describe light sources in their immediate environment.",C:"Identify objects that produce light using visual senses.",P:"Sort objects into \'produces light\' and \'does not produce light\' categories.",A:"Describe how sunlight helps them perform daily activities.",pre:"Play an \'I Spy\' sensory game: find objects that shine when window blinds open.",steps:[{n:1,t:"Paggamit ng Pandama",d:"Pupils walk around and list light-emitting objects seen (cellphones, windows, lights).",dp:["Clear goals","Scaffolding"]}],task:"Qualitative PACE checklist: can child point to light sources during observation?",rubric:"Skills observation checklist (Yes / Not Yet).",rem:"High-contrast pictorial sorting cards for one-on-one review.",enr:"Trace shadows of objects on paper outdoors.",home:"Draw 3 things at home that give light at night."}}},\n "Mathematics":{"1":{"1":{code:"M1NS-Ia-1",text:"Count the number of objects in a given set up to 10.",C:"Count sets of objects up to 10 accurately.",P:"Write numerals 1–10 to match counted sets.",A:"Show patience and care when counting classroom objects.",pre:"Sing the counting song together and count fingers.",steps:[{n:1,t:"Counting with Blocks",d:"Use coloured blocks; teacher models counting 1–10, students follow.",dp:["Scaffolding","Clear goals"]},{n:2,t:"Write the Number",d:"Students write the numeral matching their counted set on a mini whiteboard.",dp:["Active retrieval","Inclusion"]}],task:"Oral counting observation and number-writing activity in learner\'s book.",rubric:"PACE Form — Numeracy (Yes / Not Yet).",rem:"Number line poster for visual support during independent practice.",enr:"Count objects in a small bag and write the total.",home:"Count 5 items at home and draw them."}}},\n "Filipino":{"1":{"1":{code:"F1OL-Ia-a-1",text:"Nakapagsasalita tungkol sa sarili nang may tiwala at kagalangan.",C:"Sabihin ang kanilang pangalan, edad, at paboritong bagay.",P:"Magsalita ng malinaw at may ekspresyon sa harap ng klase.",A:"Ipakita ang paggalang habang nakikinig sa iba.",pre:"Awit: \'Ang Aking Pangalan\' — kantahin ng buong klase.",steps:[{n:1,t:"Pagpapakilala",d:"Bawat bata ay magsasabi ng kanilang pangalan at isang bagay na gusto nila.",dp:["Clear goals","Inclusion"]}],task:"Guro ay magmamasid at magtatala sa PACE Form.",rubric:"Yes / Not Yet — Oral Communication Checklist.",rem:"Picture cards bilang gabay sa pagpapakilala.",enr:"Iguhit ang sarili at ipaliwanag ang larawan.",home:"Ikwento sa magulang ang sariling pangalan at paboritong pagkain."}}},\n "English":{"1":{"1":{code:"EN1OL-Ia-a-1",text:"Use oral language to communicate feelings and ideas in simple sentences.",C:"Identify and name feelings (happy, sad, angry, scared) using picture cues.",P:"Express a feeling using a complete simple sentence: \'I feel ____ because ____.\'",A:"Listen respectfully when classmates share feelings.",pre:"Show feeling faces flashcards and ask pupils to mirror the expressions.",steps:[{n:1,t:"Feelings Vocabulary",d:"Teacher shows feeling cards; pupils say the feeling and act it out.",dp:["Scaffolding","Clear goals"]},{n:2,t:"Sentence Practice",d:"In pairs, students take turns completing: \'I feel ___ today because ___.\'",dp:["Social learning","Active retrieval"]}],task:"PACE observation: can the learner name and express 3 feelings?",rubric:"Yes / Not Yet — Oral Language Checklist.",rem:"Reduce to 2 target feelings; use sentence frame card.",enr:"Draw a feelings journal page showing 2 different moods.",home:"Tell a family member one thing that makes you happy and one thing that makes you sad."}}}\n }},\n "2":{ks:1,subjects:["Science","Mathematics","Filipino","English","Araling Panlipunan","MAPEH","MTB-MLE"],data:{\n "Science":{"3":{"5":{code:"S2FE-IIIi-j-5",text:"Compare brightness of light sources and identify safety practices related to light.",C:"Compare light sources by brightness.",P:"Demonstrate safe behaviour near strong light sources.",A:"Appreciate sunlight as a free and natural resource.",pre:"Discussion: Which is brighter — candle, flashlight, or sun?",steps:[{n:1,t:"Brightness Card Ranking",d:"Students sort picture cards from dimmest to brightest and explain their order.",dp:["Clear goals","Active retrieval"]}],task:"PACE Form — Science Observation.",rubric:"Yes / Not Yet checklist.",rem:"Tactile brightness cards for guided review.",enr:"Draw a night scene using different light sources.",home:"Observe and list 3 light sources at home tonight."}}}\n }},\n "3":{ks:1,subjects:["Science","Mathematics","Filipino","English","Araling Panlipunan","MAPEH","MTB-MLE"],data:{\n "Science":{"3":{"5":{code:"S3FE-IIIi-j-5.1",text:"Describe light sources and explore how light travels in a straight line through guided experiments.",C:"Classify light sources as natural (likas) or artificial (artipisyal).",P:"Demonstrate through guided experiments that light travels in a straight line.",A:"Value the practical role of light in daily safety (traffic lights, emergency flashlights).",pre:"Open-close eyes challenge: can you see colour in complete darkness? Pupils discuss.",steps:[{n:1,t:"Likas vs Artipisyal",d:"Teacher introduces natural (Sun, stars, fireflies) and artificial (bulbs, flashlights) sources via image-sort.",dp:["Clear goals","Scaffolding"]},{n:2,t:"Cardboard Hole Experiment",d:"Align 3 index cards with holes; shine flashlight through. Shift card 2 — light blocked. Light is straight!",dp:["Active retrieval","Social learning","Inclusion"]}],task:"Bilingual 5-item \'Likas o Artipisyal\' formative check.",rubric:"KS1 Qualitative Rubric — Scientific Inquiry, Collaboration, Safety.",rem:"Match card blocks with 3D tactile objects during ARAL hour.",enr:"Shadow puppet challenge behind a light source.",home:"Find 5 household light sources at night and classify them."}}},\n "Mathematics":{"3":{"5":{code:"M3NS-IIIi-j-50",text:"Perform operations on fractions with like and unlike denominators using models.",C:"Add and subtract fractions with like denominators using visual fraction bars.",P:"Model fraction addition with paper strips cut to equal parts.",A:"Show persistence when checking fraction answers with models.",pre:"Review: What is a fraction? Show pizza slices and label parts.",steps:[{n:1,t:"Fraction Bar Models",d:"Students cut equal strips to model 1/4 + 2/4 = 3/4 and similar problems.",dp:["Scaffolding","Active retrieval"]},{n:2,t:"Partner Check",d:"Pairs swap papers and verify each other\'s fraction models.",dp:["Social learning","Checks for understanding"]}],task:"5-item fraction addition worksheet with picture models.",rubric:"PACE Form — Mathematical Reasoning (Yes / Not Yet).",rem:"Colour-coded fraction wall for visual reference.",enr:"Create your own fraction story problem.",home:"Cut a piece of paper into equal parts and write a fraction to describe one part."}}}\n }},\n "4":{ks:2,subjects:["Science","Mathematics","Filipino","English","Araling Panlipunan","MAPEH","EPP/TLE"],data:{\n "Science":{"3":{"5":{code:"S4FE-IIIi-j-5",text:"Demonstrate how light behaves through reflection, absorption, and transmission using simple experiments.",C:"Explain reflection, absorption, and transmission using experimental data.",P:"Conduct experiments using mirrors, coloured paper, and transparent materials.",A:"Appreciate the science behind everyday uses of light in technology and safety.",pre:"Recapitulate Grade 3 findings: light is straight. Now: what happens when it hits something?",steps:[{n:1,t:"Mirror Reflection Experiment",d:"Students use mirrors and flashlights; observe angle of incidence equals angle of reflection.",dp:["Active retrieval","Social Learning"]},{n:2,t:"OTT Classification",d:"Students sort classroom objects into Opaque, Translucent, Transparent categories.",dp:["Scaffolding","Clear goals"]}],task:"5-item formative quiz + lab observation checklist.",rubric:"WW 20%, PT 50%, ST 30%.",rem:"Concept-map review of OTT properties.",enr:"Design a simple periscope using two mirrors.",home:"List 3 transparent, 3 translucent, and 3 opaque objects at home."}}},\n "Mathematics":{"3":{"5":{code:"M4NS-IIIi-j-70",text:"Multiply multi-digit numbers by 1- to 2-digit numbers using standard algorithm.",C:"Apply the standard multiplication algorithm to solve 3-digit by 2-digit problems.",P:"Set up and solve multiplication problems in vertical form with proper regrouping.",A:"Check work carefully and appreciate accuracy in calculation.",pre:"Warm-up: 12 × 4 — who can answer? How? Class shares strategies.",steps:[{n:1,t:"Step-by-Step Multiplication",d:"Teacher models 234 × 15 using step notation; students annotate steps in notebook.",dp:["Scaffolding","Clear goals"]},{n:2,t:"Pair Practice",d:"Students solve 5 problems in pairs, checking after each answer.",dp:["Social Learning","Active retrieval"]}],task:"10-item written multiplication drill.",rubric:"WW 20%, PT 50%, ST 30%.",rem:"Multiplication table reference card for independent work.",enr:"Solve a real-world multi-step problem involving multiplication.",home:"Compute the total cost of 3 grocery items with your family."}}},\n "Filipino":{"3":{"5":{code:"F4RC-IIIi-j-3",text:"Natutukoy ang mga pangunahing ideya at detalye mula sa tekstong babasahin.",C:"Tukuyin ang pangunahing ideya at tatlong detalye ng isang maikling teksto.",P:"Isulat ang pangunahing ideya at sumusuportang detalye sa graphic organizer.",A:"Magpakita ng malalim na pag-unawa sa nilalaman ng akda.",pre:"Ipakita ang larawan; itanong: Ano ang isinasalaysay ng larawan?",steps:[{n:1,t:"Pagbabasa ng Teksto",d:"Guro ay magbabasa ng maikling kwento; mga mag-aaral ay mag-iisip habang nakikinig.",dp:["Scaffolding","Active retrieval"]},{n:2,t:"Graphic Organizer",d:"Mag-aaral ay kukumpletuhin ang Main Idea + 3 Details na graphic organizer.",dp:["Clear goals","Social Learning"]}],task:"5-item comprehension check.",rubric:"WW 20%, PT 50%, ST 30%.",rem:"Simplified text with picture cues for struggling readers.",enr:"Sumulat ng sariling maikling kwento na may pangunahing ideya.",home:"Basahin ang isang pahayagan at hanapin ang pangunahing ideya ng isang balita."}}}\n }},\n "5":{ks:2,subjects:["Science","Mathematics","Filipino","English","Araling Panlipunan","MAPEH","EPP/TLE"],data:{\n "Science":{"3":{"5":{code:"S5FE-IIIi-j-5",text:"Explain how light interacts with lenses and prisms to produce focus, dispersion, and colour separation.",C:"Explain how convex and concave lenses focus and diverge light.",P:"Observe colour dispersion using a prism and document results in a data table.",A:"Connect optics knowledge to real-world uses — eyeglasses, cameras, projectors.",pre:"Prism demonstration: white light disperses into ROYGBIV. What is happening?",steps:[{n:1,t:"Lens Types Comparison",d:"Students examine convex/concave lenses, draw ray diagrams, note convergence vs divergence.",dp:["Clear goals","Active retrieval"]},{n:2,t:"Prism Rainbow Activity",d:"Groups place prisms near a window; observe and record colour sequence in data sheets.",dp:["Social Learning","Scaffolding"]}],task:"10-item formative identification quiz + ray diagram task.",rubric:"WW 20%, PT 50%, ST 30%.",rem:"Colour-labelled lens diagram reference for review.",enr:"Research how the human eye works like a lens system.",home:"Observe how eyeglasses or magnifiers bend light; write your observations."}}},\n "Mathematics":{"3":{"5":{code:"M5NS-IIIi-j-90",text:"Solve problems involving division of decimals and mixed numbers.",C:"Divide decimals and mixed numbers using the standard algorithm.",P:"Set up and solve decimal division problems in vertical form.",A:"Verify answers and discuss reasonableness of results with peers.",pre:"Review: How is dividing whole numbers the same as dividing decimals? Students share ideas.",steps:[{n:1,t:"Decimal Division Algorithm",d:"Teacher models 12.6 ÷ 3 and 4.5 ÷ 1.5; students annotate process.",dp:["Scaffolding","Clear goals"]},{n:2,t:"Real-World Problems",d:"Students solve 3 word problems involving money or measurement using decimal division.",dp:["Active retrieval","Social Learning"]}],task:"6-item written formative quiz.",rubric:"WW 20%, PT 50%, ST 30%.",rem:"Number line model for decimal placement review.",enr:"Create a shopping budget scenario that requires decimal division.",home:"Divide a family food bill among household members; show working."}}},\n "English":{"3":{"5":{code:"EN5RC-IIIi-2",text:"Identify and analyse cause-and-effect relationships in informational texts.",C:"Distinguish cause from effect in informational paragraphs.",P:"Complete a cause-and-effect graphic organizer based on a given text.",A:"Appreciate how understanding cause-effect relationships helps in critical reading.",pre:"Quick visual: show domino effect picture. What caused the dominoes to fall?",steps:[{n:1,t:"Signal Words Hunt",d:"Students highlight cause (because, since, due to) and effect (therefore, so, as a result) signal words in a sample text.",dp:["Active retrieval","Clear goals"]},{n:2,t:"Graphic Organizer",d:"Pairs complete a cause-effect web based on a short news article extract.",dp:["Social Learning","Scaffolding"]}],task:"5-item formative comprehension exercise.",rubric:"WW 20%, PT 50%, ST 30%.",rem:"Sentence frame: \'The cause was ___ therefore the effect was ___.\'",enr:"Write an original paragraph with one cause and two effects.",home:"Find a news headline and identify the cause and effect described."}}},\n "Araling Panlipunan":{"3":{"5":{code:"AP5PKB-IIIi-j-7",text:"Ipaliwanag ang papel ng mga likas na yaman sa pag-unlad ng ekonomiya ng Pilipinas.",C:"Tukuyin ang tatlong pangunahing likas na yaman ng Pilipinas at ang kanilang kaugnayan sa ekonomiya.",P:"Gumawa ng isang simpleng mapa na nagpapakita ng distribusyon ng likas na yaman sa iba\'t ibang rehiyon.",A:"Pagpapakita ng pagmamahal sa kalikasan at responsableng paggamit ng likas na yaman.",pre:"Ipakita ang mapa ng Pilipinas — saan matatagpuan ang mga pangunahing likas na yaman?",steps:[{n:1,t:"Likas na Yaman Bilang Kayamanan",d:"Grupo ay gagawa ng talaan ng likas na yaman (mineral, kagubatan, karagatan) sa kanilang lalawigan.",dp:["Clear goals","Social Learning"]},{n:2,t:"Resource Map Activity",d:"Mag-aaral ay maglalagay ng simbolo ng likas na yaman sa simpleng mapa ng Pilipinas.",dp:["Scaffolding","Active retrieval"]}],task:"5-item formative identification quiz.",rubric:"WW 20%, PT 50%, ST 30%.",rem:"Picture-labelled reference card ng likas na yaman.",enr:"Magsaliksik tungkol sa isang nanganganib na likas na yaman at magsulat ng rekomendasyon.",home:"Itanong sa magulang kung anu-anong likas na yaman ang ginagamit ng pamilya araw-araw."}}}\n }},\n "6":{ks:2,subjects:["Science","Mathematics","Filipino","English","Araling Panlipunan","MAPEH","EPP/TLE"],data:{\n "Science":{"3":{"5":{code:"S6FE-IIIi-j-5",text:"Describe the electromagnetic spectrum and position visible light within the full range of EM radiation.",C:"Describe the EM spectrum from radio waves to gamma rays, in order of frequency.",P:"Arrange EM spectrum cards in order of increasing frequency and energy.",A:"Appreciate practical applications of EM radiation in medicine and communication.",pre:"Quick recall: visible light spectrum — name the colours. Where does this fit in a bigger picture?",steps:[{n:1,t:"Spectrum Card Sort",d:"Students sort labelled EM spectrum cards by wavelength and energy level and justify order.",dp:["Active retrieval","Scaffolding"]},{n:2,t:"Real-World Application Match",d:"Match each EM type to its application: radio→broadcast, X-ray→medical imaging, UV→sterilisation.",dp:["Clear goals","Social Learning"]}],task:"10-item EM spectrum identification and classification quiz.",rubric:"WW 20%, PT 50%, ST 30%.",rem:"Mnemonic: \'Radio Men In Vests Use X-ray Goggles\' for recall.",enr:"Research how UV radiation affects skin cells; present findings.",home:"Identify 5 household devices that use EM radiation and classify each."}}}\n }},\n "7":{ks:3,subjects:["Science","Mathematics","Filipino","English","Araling Panlipunan","MAPEH","TLE","Values Education"],data:{\n "Science":{"3":{"5":{code:"S7FE-IIIg-20",text:"Describe wave characteristics and differentiate mechanical from electromagnetic waves.",C:"Differentiate mechanical and electromagnetic waves using observable properties.",P:"Draw labelled wave diagrams showing amplitude, wavelength, frequency, and crest.",A:"Recognise how wave properties explain energy transfer in daily life.",pre:"Slinky demonstration: push-pull creates longitudinal; side-to-side creates transverse. Which is which?",steps:[{n:1,t:"Wave Properties Diagram",d:"Students label amplitude, wavelength, crest, trough, and compute frequency given period.",dp:["Scaffolding","Clear goals"]},{n:2,t:"Mechanical vs EM Debate Cards",d:"Groups argue properties of assigned wave types; compare using structured comparison matrices.",dp:["Social Learning","Active retrieval"]}],task:"15-item formative test on wave properties + diagram performance task.",rubric:"WW 20%, PT 50%, ST 30%.",rem:"Wave property summary poster for guided review.",enr:"Research how seismographs use wave mechanics to detect earthquakes.",home:"Observe and describe 3 examples of wave motion in your home environment."}}},\n "Mathematics":{"3":{"5":{code:"M7AL-IIIi-j-2",text:"Solve problems involving linear equations and inequalities in one variable.",C:"Apply properties of equality to isolate the variable in linear equations.",P:"Solve multi-step linear equations and check solutions by substitution.",A:"Value systematic thinking and verification in solving mathematical problems.",pre:"Puzzler: \'I am thinking of a number. When I double it and add 5, I get 17. What is it?\'",steps:[{n:1,t:"Properties of Equality",d:"Teacher models solving 3x + 5 = 17 step-by-step; students annotate each property used.",dp:["Scaffolding","Clear goals"]},{n:2,t:"Independent Equation Solving",d:"Students solve 6 linear equations and verify by substituting solutions back.",dp:["Active retrieval","Self-awareness and Metacognition"]}],task:"10-item written formative — solve and verify.",rubric:"WW 20%, PT 50%, ST 30%.",rem:"Equation balance model using scale diagram for visual learners.",enr:"Write and solve a word problem that requires a two-step linear equation.",home:"Write an equation for a real-life situation at home (e.g. sharing food equally) and solve it."}}},\n "English":{"3":{"5":{code:"EN7RC-IIIi-j-8",text:"Distinguish between fact and opinion in informational and persuasive texts.",C:"Identify markers of fact (verifiable data) and opinion (belief, judgment) in written texts.",P:"Annotate a persuasive article marking facts (F) and opinions (O) for each claim.",A:"Develop critical reading habits by questioning the basis of claims in media.",pre:"Display a newspaper headline. Ask: Is this a fact or an opinion? How do you know?",steps:[{n:1,t:"Fact vs Opinion Markers",d:"Students study a sample editorial; highlight verifiable claims in blue, opinions in yellow.",dp:["Active retrieval","Clear goals"]},{n:2,t:"Pair Annotation Challenge",d:"Pairs annotate a new text and defend their F/O labels to another group.",dp:["Social Learning","Self-awareness and Metacognition"]}],task:"10-item formative F/O identification exercise.",rubric:"WW 20%, PT 50%, ST 30%.",rem:"Reference card: fact markers (statistics, dates, measurements) vs opinion markers (should, best, I believe).",enr:"Write a short editorial paragraph mixing facts and opinions; highlight both.",home:"Read a social media post and identify which claims are facts and which are opinions."}}}\n }},\n "8":{ks:3,subjects:["Science","Mathematics","Filipino","English","Araling Panlipunan","MAPEH","TLE","Values Education"],data:{\n "Science":{"3":{"5":{code:"S8FE-IIIg-26",text:"Explain light propagation, reflection, and refraction through both wave and particle models.",C:"Differentiate wave-particle models and apply Snell\'s Law to calculate refraction angles.",P:"Construct ray diagrams showing refraction through convex lenses and prisms.",A:"Connect optics knowledge to corrective eyewear technology and student well-being.",pre:"Review wave behaviours with slinky demo; introduce the question: Is light a wave or a particle?",steps:[{n:1,t:"Wave vs Particle Model",d:"Students contrast Huygens\' Wave Theory with Newton\'s Corpuscular Theory via comparison matrix.",dp:["Active retrieval","Self-awareness and Metacognition"]},{n:2,t:"Snell\'s Law Lab",d:"Students measure angles of incidence and refraction through glass slabs; compute n = sin θ₁/sin θ₂.",dp:["Scaffolding","Social Learning"]}],task:"10-item MCQ formative test + Snell\'s Law calculation items.",rubric:"WW 20%, PT 50%, ST 30%. Passing: raw ≥70% → transmuted grade ≥75%.",rem:"Peer-guided tutorial on refractive index calculations.",enr:"Research optical illusions in nature — mirages and rainbows; draft an explanation slide.",home:"Classify home light fixtures as reflective or diffusive; record in log journal."}}},\n "Mathematics":{"3":{"5":{code:"M8GE-IIIi-j-5",text:"Prove geometric theorems involving triangles using deductive reasoning.",C:"Identify postulates and theorems needed to prove triangle congruence (SSS, SAS, ASA, AAS).",P:"Construct a two-column proof for a given pair of congruent triangles.",A:"Appreciate logical reasoning as a life skill beyond mathematics.",pre:"Display two triangles. Ask: How do we know these are exactly the same shape and size?",steps:[{n:1,t:"Congruence Postulate Review",d:"Students identify the minimum conditions (SSS, SAS, ASA, AAS) using triangle cut-outs.",dp:["Active retrieval","Scaffolding"]},{n:2,t:"Two-Column Proof Practice",d:"Students complete a guided two-column proof template, supplying justifications for each step.",dp:["Self-awareness and Metacognition","Clear goals"]}],task:"One proof construction task + 5 identification items.",rubric:"WW 20%, PT 50%, ST 30%.",rem:"Annotated sample proof for guided study.",enr:"Research the real-world application of triangle congruence in bridge engineering.",home:"Sketch a real object (table, roof, bridge) and identify congruent triangles within it."}}},\n "Filipino":{"3":{"5":{code:"F8PL-IIIi-j-7",text:"Nasusuri ang mga pahayag para sa layunin, tono, at pagpapahalaga ng may-akda.",C:"Matukoy ang layunin, tono, at pananaw ng may-akda sa isang tekstong pampanitikan.",P:"Sumulat ng maikling pagsusuri na may ebidensya mula sa teksto.",A:"Mapaunlad ang kritikal na pag-iisip sa pamamagitan ng pagtatanong sa layunin ng teksto.",pre:"Ibahagi ang isang maikling tula. Itanong: Nakaramdam ba kayo ng damdamin habang ito ay binabasa?",steps:[{n:1,t:"Layunin at Tono",d:"Sama-samang tukuyin ang layunin ng teksto; makilala ang mga salitang nagpapahiwatig ng tono.",dp:["Clear goals","Active retrieval"]},{n:2,t:"Pagsusuri ng Pananaw",d:"Mag-aaral ay sumusulat ng isang talata ng pagsusuri gamit ang IBT (Ideya-Batayan-Tono) na balangkas.",dp:["Scaffolding","Social Learning"]}],task:"Isang maikling pagsusuri na binibigyan ng marka ayon sa rubric.",rubric:"WW 20%, PT 50%, ST 30%.",rem:"Simpleng IBT graphic organizer para sa mga nangangailangan ng tulong.",enr:"Ihambing ang dalawang maikling tula ng magkaibang may-akda.",home:"Hanapin ang isang patalastas sa TV o social media at suriin ang layunin at tono nito."}}}\n }},\n "9":{ks:3,subjects:["Science","Mathematics","Filipino","English","Araling Panlipunan","MAPEH","TLE","Values Education"],data:{\n "Science":{"3":{"5":{code:"S9FE-IIIg-30",text:"Apply mirror and lens formulas to explain real and virtual image formation.",C:"Apply the mirror formula 1/f = 1/do + 1/di to compute image distance and characterise images.",P:"Set up mirror/lens experiments and measure image characteristics; construct ray diagrams.",A:"Appreciate how image formation powers medical, media, and communication technology.",pre:"Concave mirror demo with candle: image appears inverted at a distance. Why?",steps:[{n:1,t:"Mirror Formula Application",d:"Students solve for image distance and classify images (real/virtual, upright/inverted, enlarged/reduced).",dp:["Checks for understanding","Active retrieval"]},{n:2,t:"Lens Optical Bench Lab",d:"Groups measure focal length of converging lens; compare to manufacturer specification.",dp:["Social Learning","Scaffolding"]}],task:"5-item calculation formative quiz + lab report PT.",rubric:"WW 20%, PT 50%, ST 30%.",rem:"Annotated formula reference cards.",enr:"Design a simple telescope or microscope using available lenses.",home:"Investigate how your phone camera uses lens principles; sketch the system."}}},\n "Mathematics":{"3":{"5":{code:"M9AL-IIIi-j-4",text:"Solve systems of linear equations in two variables using substitution and elimination.",C:"Choose the appropriate method (substitution or elimination) to solve a system.",P:"Solve a system of two linear equations and verify by substitution.",A:"Recognise real-world situations that require simultaneous solutions.",pre:"Puzzle: \'Two numbers sum to 10 and differ by 2. What are they?\' Students attempt different strategies.",steps:[{n:1,t:"Substitution Method",d:"Teacher models: if y = 2x, substitute into x + y = 9 to solve. Students replicate.",dp:["Scaffolding","Clear goals"]},{n:2,t:"Elimination Method",d:"Students solve 3x + 2y = 12 and x - y = 1 by multiplying to eliminate one variable.",dp:["Active retrieval","Self-awareness and Metacognition"]}],task:"6-item mixed-method written formative.",rubric:"WW 20%, PT 50%, ST 30%.",rem:"Step-by-step substitution algorithm reference card.",enr:"Model a real-world scenario (e.g. ticket pricing) as a system and solve.",home:"Write a number puzzle for a family member that requires two equations to solve."}}}\n }},\n "10":{ks:3,subjects:["Science","Mathematics","Filipino","English","Araling Panlipunan","MAPEH","TLE","Values Education"],data:{\n "Science":{"3":{"5":{code:"S10FE-IIIh-50",text:"Explain interference and diffraction of light using the wave model.",C:"Apply Young\'s double-slit equations to calculate fringe spacing.",P:"Observe diffraction patterns and sketch bright and dark fringe positions.",A:"Connect diffraction principles to spectroscopy, holography, and anti-counterfeiting technology.",pre:"Laser through double-slit demo: pattern on screen. Students describe what they see.",steps:[{n:1,t:"Young\'s Double-Slit Analysis",d:"Students compute fringe spacing using y = λL/d and compare theoretical to observed values.",dp:["Self-awareness and Metacognition","Active retrieval"]},{n:2,t:"Pattern Sketching Lab",d:"Groups sketch and label bright and dark fringes from their own lab observation.",dp:["Social Learning","Clear goals"]}],task:"10-item written test on wave optics + calculation PT.",rubric:"WW 20%, PT 50%, ST 30%.",rem:"Annotated diagrams to revisit phase-difference concept.",enr:"Research how diffraction gratings work in spectroscopes; prepare a diagram.",home:"Observe iridescence in soap bubbles or CDs; explain the interference principle in writing."}}},\n "Mathematics":{"3":{"5":{code:"M10AL-IIIi-j-7",text:"Determine the general term of sequences and solve problems involving arithmetic and geometric sequences.",C:"Identify the common difference or ratio and write the general term formula for a sequence.",P:"Use aₙ = a₁ + (n-1)d and aₙ = a₁·r^(n-1) to find specified terms.",A:"Recognise patterns in nature and design as manifestations of mathematical sequences.",pre:"Show: 2, 5, 8, 11… and 2, 6, 18, 54… Ask: What patterns do you see?",steps:[{n:1,t:"Arithmetic Sequence Formula",d:"Students identify d; use aₙ = a₁ + (n−1)d to find the 10th and 20th terms.",dp:["Scaffolding","Clear goals"]},{n:2,t:"Geometric Sequence Formula",d:"Students identify r; compute specified terms and write the general term formula.",dp:["Active retrieval","Self-awareness and Metacognition"]}],task:"10-item written formative — identify type, find terms.",rubric:"WW 20%, PT 50%, ST 30%.",rem:"Sequence formula reference card with worked examples.",enr:"Research the Fibonacci sequence in nature; identify 5 real-world examples.",home:"Write your own arithmetic or geometric sequence using objects at home (e.g. stacked coins, savings)."}}}\n }},\n "11":{ks:4,subjects:["General Physics 1","General Mathematics","Oral Communication","Reading & Writing Skills","Understanding Culture, Society and Politics","Personal Development","Earth and Life Science","Media and Information Literacy","21st Century Literature","Contemporary Philippine Arts"],data:{\n "General Physics 1":{"3":{"5":{code:"STEM_GP12WP-IIIb-20",text:"Apply wave motion principles to explain propagation and characteristics of mechanical and electromagnetic waves.",C:"Calculate wave speed, frequency, and wavelength using v = fλ for real scenarios.",P:"Use a wave simulation or physical demonstration to measure wave parameters.",A:"Reflect on how wave physics underpins modern communication technology.",pre:"Review wave diagrams; students brainstorm: where do we encounter waves every day?",steps:[{n:1,t:"Wave Speed Calculations",d:"Students compute v = fλ for ocean waves, sound in air, and light in glass.",dp:["Checks for understanding","Active retrieval"]},{n:2,t:"Measurement Lab",d:"Using a slinky or wave tank, students measure amplitude, wavelength, and frequency directly.",dp:["Social Learning","Self-awareness and Metacognition"]}],task:"Quantitative 10-item problem set + lab report.",rubric:"WW 20%, PT 50%, ST 30% — Senior High School weights.",rem:"Wave equation drill with annotated solutions.",enr:"Research sonar and radar wave-property applications.",home:"Calculate the wavelength of an FM radio station given its broadcast frequency."}}},\n "General Mathematics":{"3":{"5":{code:"SHS_GM-IIIi-j-20",text:"Solve problems involving rational functions, equations, and inequalities.",C:"Determine the domain, range, and intercepts of rational functions.",P:"Solve rational equations by finding the LCD and verify solutions.",A:"Appreciate how rational functions model real-world scenarios such as rates, time, and work.",pre:"Review: what makes a fraction undefined? Apply to f(x) = 1/(x-2).",steps:[{n:1,t:"Rational Function Analysis",d:"Students find domain (exclude denominator zeros), x- and y-intercepts for 3 rational functions.",dp:["Clear goals","Active retrieval"]},{n:2,t:"Solving Rational Equations",d:"Students solve (x+1)/(x-2) = 3 by multiplying both sides by LCD; check for extraneous solutions.",dp:["Scaffolding","Checks for understanding"]}],task:"8-item written formative — solve and verify.",rubric:"WW 20%, PT 50%, ST 30%.",rem:"LCD identification algorithm reference card.",enr:"Graph a rational function and identify asymptotes using Desmos.",home:"Write a word problem that models a work-rate scenario using a rational equation."}}},\n "Oral Communication":{"3":{"5":{code:"OC11/12OP-IIIi-j-10",text:"Deliver a well-organised speech using clear pronunciation, appropriate pace, and effective non-verbal cues.",C:"Identify the components of effective oral delivery (pronunciation, rate, volume, eye contact, gestures).",P:"Deliver a 3-minute prepared speech applying all delivery components.",A:"Build confidence in public speaking by reflecting on strengths and areas for growth.",pre:"Show a short clip of an effective and an ineffective speaker. Students list differences.",steps:[{n:1,t:"Delivery Components Analysis",d:"Students use a rubric to evaluate the clip speakers; discuss: what made one more effective?",dp:["Active retrieval","Self-awareness and Metacognition"]},{n:2,t:"Prepared Speech Delivery",d:"Students deliver their 3-minute speeches; peers use a peer-evaluation form.",dp:["Social Learning","Checks for understanding"]}],task:"Speech delivery scored on Delivery Rubric (PT 50%).",rubric:"WW 20%, PT 50%, ST 30%.",rem:"Provide sentence starters and outline template for struggling speakers.",enr:"Record speech and analyse delivery video for self-assessment.",home:"Practice the speech to a family member and note their feedback."}}},\n "Personal Development":{"3":{"5":{code:"PD11/12EsP-IIIi-j-3",text:"Reflect on personal strengths, limitations, and experiences that influence personal development.",C:"Identify personal strengths and limitations using validated self-assessment tools.",P:"Complete a Johari Window analysis and share insights with a trusted peer.",A:"Show openness to feedback as a foundation for lifelong self-improvement.",pre:"Journal entry prompt: \'What are 3 things you do well and 1 thing you would like to improve?\'",steps:[{n:1,t:"Johari Window Activity",d:"Students fill in quadrants: known-known, blind spot, facade, unknown; discuss with a partner.",dp:["Self-awareness and Metacognition","Social Learning"]},{n:2,t:"Strength-Limitation Reflection",d:"Students write a structured reflection: strength → evidence → plan for a limitation.",dp:["Clear goals","Checks for understanding"]}],task:"Written reflection rubric-scored + Johari Window PT.",rubric:"WW 20%, PT 50%, ST 30%.",rem:"Pre-filled Johari Window template for guided completion.",enr:"Research a historical figure; analyse their Johari Window based on biographical evidence.",home:"Interview a trusted family member about your blind spot; write a response journal entry."}}}\n }},\n "12":{ks:4,subjects:["General Physics 2","Practical Research 2","Oral Communication","Contemporary Philippine Arts","21st Century Literature","Physical Education and Health","Entrepreneurship","Earth Science"],data:{\n "General Physics 2":{"3":{"5":{code:"SPH12-IIIh-55",text:"Explain optical phenomena through wave-particle and photon theories and relate photon energy to EM frequencies.",C:"Calculate photon energy using Planck\'s equation E = hf; explain the Photoelectric Effect.",P:"Derive kinetic energy of photoelectrons given light frequency and work function of metals.",A:"Appreciate how quantum physics principles enable solar panel technology and clean energy.",pre:"Retrieve classical wave concepts; introduce ultraviolet catastrophe as trigger for quantum physics.",steps:[{n:1,t:"Photoelectric Effect — Einstein\'s Theory",d:"Derive E = hf; explain work function; solve for Ek = hf - φ using quantitative problem sets.",dp:["Checks for understanding","Self-awareness and Metacognition"]},{n:2,t:"Stopping Potential Calculations",d:"Students calculate stopping potential for various photoelectric targets and compare theoretical values.",dp:["Active retrieval","Scaffolding"]}],task:"8-item calculation-based formative on photon energy and stopping potentials.",rubric:"WW 20%, PT 50%, ST 30% — Senior High School weights.",rem:"Computational practice loop with annotated solution keys.",enr:"Present implications of Time Dilation on optical satellite communications.",home:"Draw a schematic of a home solar inverter converting light photon input to AC electricity."}}},\n "Practical Research 2":{"3":{"5":{code:"PR211-IIIi-j-15",text:"Interpret quantitative data using descriptive and inferential statistics and present findings clearly.",C:"Interpret mean, median, mode, standard deviation, and correlation coefficients from research data.",P:"Use statistical software or spreadsheet to compute and visualise descriptive statistics.",A:"Maintain academic integrity by accurately representing data without manipulation.",pre:"Show a data set; ask: What story does this data tell? What do these numbers mean?",steps:[{n:1,t:"Descriptive Statistics Review",d:"Students compute measures of central tendency and variability for a provided data set.",dp:["Active retrieval","Checks for understanding"]},{n:2,t:"Data Visualisation",d:"Students create an appropriate chart (bar, histogram, scatter) for their data in a spreadsheet.",dp:["Self-awareness and Metacognition","Clear goals"]}],task:"Data interpretation report — PT 50%.",rubric:"WW 20%, PT 50%, ST 30%.",rem:"Statistics formula reference sheet + calculator tutorial.",enr:"Run a Pearson correlation analysis on two research variables and interpret r.",home:"Identify the type of chart used in a news article and evaluate whether it accurately represents the data."}}},\n "Entrepreneurship":{"3":{"5":{code:"ENT12-IIIi-j-8",text:"Develop a detailed business plan including marketing, operations, and financial projections.",C:"Identify the four components of a business plan (executive summary, marketing, operations, financials).",P:"Draft the marketing and operations sections for a student enterprise concept.",A:"Develop entrepreneurial confidence by connecting classroom learning to real business scenarios.",pre:"Mini pitch: \'You have P500 and 1 week. What business would you start?\' Students share ideas.",steps:[{n:1,t:"Business Plan Structure",d:"Teacher presents a sample business plan; students identify each section and its purpose.",dp:["Clear goals","Active retrieval"]},{n:2,t:"Marketing & Operations Draft",d:"Small groups draft the marketing mix (4Ps) and an operations timeline for their enterprise idea.",dp:["Social Learning","Self-awareness and Metacognition"]}],task:"Business plan section draft — scored using Entrepreneurship PT rubric.",rubric:"WW 20%, PT 50%, ST 30%.",rem:"Guided business plan template with sentence starters per section.",enr:"Conduct a 5-person market survey and integrate data into the marketing section.",home:"Interview a local entrepreneur about their planning process; incorporate insights into the draft."}}}\n }}\n};\n/* Grade-to-Key-Stage resolver */\nfunction ksOf(g){const n=parseInt(g);if(n<=3)return 1;if(n<=6)return 2;if(n<=10)return 3;return 4;}\nfunction ksLabel(ks){return["","Key Stage 1 · Grades 1–3","Key Stage 2 · Grades 4–6","Key Stage 3 · Grades 7–10","Key Stage 4 · Grades 11–12"][ks];}\n/* ═══════════ QUILL INIT (runs after DOM ready) ═══════════ */\nlet quill, _saveT;\n/* ═══════════ TAB SWITCHING ═══════════ */\nfunction switchTab(t){\n [\'plan\',\'calc\',\'about\'].forEach(id=>{\n document.getElementById(\'panel-\'+id).classList.toggle(\'active\',id===t);\n document.getElementById(\'tab-\'+id).classList.toggle(\'active\',id===t);\n });\n}\n/* ═══════════ CASCADING DROPDOWNS (wired in DOMContentLoaded) ═══════════ */\nfunction initDropdowns(){\ndocument.getElementById(\'sel-grade\').addEventListener(\'change\',function(){\n const g=this.value, ks=g?ksOf(g):null;\n const wrap=document.getElementById(\'ks-wrap\'), badge=document.getElementById(\'ks-badge\');\n const subSel=document.getElementById(\'sel-subject\');\n subSel.innerHTML=\'<option value="">— Subject —</option>\';\n document.getElementById(\'sel-week\').innerHTML=\'<option value="">— Wk —</option>\';\n if(g&&DB[g]){\n wrap.style.display=\'block\';\n badge.textContent=ksLabel(ks);\n DB[g].subjects.forEach(s=>{const o=document.createElement(\'option\');o.value=s;o.textContent=s;subSel.appendChild(o);});\n } else {\n wrap.style.display=\'none\';\n }\n document.getElementById(\'doc-lbl\').textContent=g?`Grade ${g} · ${ksLabel(ks)||\'\'}` :\'Select grade & subject to begin\';\n // Update grade calc tab\n const ks1note=document.getElementById(\'calc-ks1-note\');\n const calcFields=document.getElementById(\'calc-fields\').querySelectorAll(\'input\');\n if(ks&&ks===1){ks1note.style.display=\'block\';calcFields.forEach(f=>f.disabled=true);}\n else{ks1note.style.display=\'none\';calcFields.forEach(f=>f.disabled=false);}\n});\ndocument.getElementById(\'sel-q\').addEventListener(\'change\',function(){\n const wk=document.getElementById(\'sel-week\');\n wk.innerHTML=\'<option value="">— Wk —</option>\';\n if(this.value)for(let w=1;w<=10;w++){const o=document.createElement(\'option\');o.value=w;o.textContent=`Week ${w}`;wk.appendChild(o);}\n});\n} // end initDropdowns\n/* ═══════════ GRADE CALCULATOR ═══════════ */\nfunction computeGrade(){\n const wwr=+document.getElementById(\'ww-raw\').value||0, wwt=+document.getElementById(\'ww-total\').value||1;\n const ptr=+document.getElementById(\'pt-raw\').value||0, ptt=+document.getElementById(\'pt-total\').value||1;\n const str=+document.getElementById(\'st-raw\').value||0, stt=+document.getElementById(\'st-total\').value||1;\n if(!document.getElementById(\'ww-total\').value)return;\n const ww=(wwr/wwt)*100, pt=(ptr/ptt)*100, st=(str/stt)*100;\n const init=ww*0.20+pt*0.50+st*0.30;\n const transmuted=transmute(init);\n const res=document.getElementById(\'grade-result\');\n res.style.display=\'block\';\n document.getElementById(\'grade-val\').textContent=transmuted.toFixed(2)+\'%\';\n const pass=transmuted>=75;\n const statusEl=document.getElementById(\'grade-status\');\n statusEl.textContent=pass?\'✓ Passed\':\'✗ Did Not Meet Standards\';\n statusEl.style.color=pass?\'#4ade80\':\'#f87171\';\n document.getElementById(\'grade-breakdown\').textContent=`WW: ${ww.toFixed(1)}% · PT: ${pt.toFixed(1)}% · ST: ${st.toFixed(1)}% · Initial: ${init.toFixed(2)}%`;\n}\nfunction transmute(initial){\n if(initial>=100)return 100;\n const t=[[100,100],[98.40,99],[96.80,98],[95.20,97],[93.60,96],[92,95],[90.40,94],[88.80,93],[87.20,92],[85.60,91],[84,90],[82.40,89],[80.80,88],[79.20,87],[77.60,86],[76,85],[74.40,84],[72.80,83],[71.20,82],[69.60,81],[68,80],[66.40,79],[64.80,78],[63.20,77],[61.60,76],[60,75],[56,74],[52,73],[48,72],[44,71],[40,70],[36,69],[32,68],[28,67],[24,66],[20,65],[16,64],[12,63],[8,62],[4,61],[0,60]];\n for(const[raw,grade]of t){if(initial>=raw)return grade;}\n return 60;\n}\n/* ═══════════ TEMPLATE GENERATOR ═══════════ */\nfunction generateTemplate(){\n const grade=document.getElementById(\'sel-grade\').value;\n const subject=document.getElementById(\'sel-subject\').value;\n const q=document.getElementById(\'sel-q\').value;\n const week=document.getElementById(\'sel-week\').value;\n if(!grade||!subject||!q||!week){showToast(\'⚠ Select grade, subject, quarter and week first.\');return;}\n const comp=DB[grade]?.data?.[subject]?.[q]?.[week]||buildGeneric(grade,subject,q,week);\n const html=buildHTML({grade,subject,q,week,comp});\n quill.clipboard.dangerouslyPasteHTML(html);\n autoSave();\n showToast(\'✓ Template lesson plan generated!\');\n}\n/* ═══════════ AI GENERATOR ═══════════ */\nasync function generateWithAI(){\n const grade=document.getElementById(\'sel-grade\').value;\n const subject=document.getElementById(\'sel-subject\').value;\n const q=document.getElementById(\'sel-q\').value;\n const week=document.getElementById(\'sel-week\').value;\n const customMELC=document.getElementById(\'t-melc\').value.trim();\n if(!grade||!subject||!q){showToast(\'⚠ Select grade, subject, and quarter first.\');return;}\n const ks=ksOf(grade);\n const templateComp=DB[grade]?.data?.[subject]?.[q]?.[week];\n const baseComp=templateComp||buildGeneric(grade,subject,q,week);\n const melcText=customMELC||baseComp.text;\n const gradeLabel=`Grade ${grade} (${ksLabel(ks)})`;\n const assessment=ks===1?\'Use a qualitative PACE Form with Yes/Not Yet observation. Do NOT include numerical grading.\':\'Use written works (WW 20%), performance tasks (PT 50%), and summative tests (ST 30%).\';\n const tierPref=document.getElementById(\'sel-tier\').value;\n const diverse=document.getElementById(\'tog-diverse\').checked;\n const lr=document.getElementById(\'tog-lr\').checked;\n const values=document.getElementById(\'tog-values\').checked;\n const prompt=`You are a DepEd-certified curriculum designer in the Philippines writing an ILAW lesson plan under DO No. 016, s. 2026.\nContext:\n- Grade: ${gradeLabel}\n- Key Stage: ${ks}\n- Subject: ${subject}\n- Quarter: Q${q}${week?`, Week ${week}`:\'\'}\n- MELC: "${melcText}"\n- Emergency Tier: ${tierPref}\n- Diverse Learners: ${diverse}\n- Low-Resource Environment: ${lr}\n- Values Integration: ${values}\nWrite a COMPLETE and DETAILED ILAW lesson plan in HTML using the exact CSS classes provided.\nCRITICAL RULES:\n1. If Key Stage 1 (Grades 1–3): Do NOT include grading percentages or transmutation tables. Use PACE Form assessment only.\n2. If Key Stage 2–4: Include the WW/PT/ST grading table (20%/50%/30%) and the transmutation formula.\n3. Emergency tier "${tierPref}": ${\n tierPref===\'normal\'?\'Standard classroom instruction.\':\n tierPref===\'hinay\'?\'Include a Hinay hybrid section with Self-Learning Packet distribution notes.\':\n tierPref===\'hinga\'?\'Replace classroom instruction with home-based modular procedures and 12-hour call-tree check-in protocol.\':\n \'Academic lessons are SUSPENDED. Replace instruction with full PFA / trauma-informed check-in procedures. Do not include academic content.\'\n}\n4. ${diverse?\'Include a Diverse Learner Accommodations block (class lp-acc) with Key Stage-appropriate modifications.\':\'\'}\n5. ${lr?\'Add Low-Resource Environment alternatives (class lp-lr) replacing standard materials with local/recycled substitutes.\':\'\'}\n6. ${values?\'Embed a Values Integration note connecting lesson content to national values (maka-Diyos, makatao, makakalikasan, makabansa).\':\'\'}\nUse these CSS classes for structure:\n- .lp-hdr (header block)\n- .lp-meta (metadata table) \n- .lp-sh (section header: I, L, A, W)\n- .lp-ssh (subsection header)\n- .lp-body (body text)\n- .lp-obj (CPA objectives table with .ol class for label cells)\n- .lp-step (each flow step, with .lp-step-title inside)\n- .lp-dp (design principles note)\n- .lp-gt (grading table, if KS2+)\n- .lp-pace (PACE form table, if KS1)\n- .lp-acc (accommodation block)\n- .lp-em (emergency tier block)\n- .lp-lr (low-resource block)\n- .lp-sig (signature table)\nTeacher: ${document.getElementById(\'t-name\').value||\'[Teacher Name]\'}\nSchool: ${document.getElementById(\'t-school\').value||\'[School Name]\'}\nSection: ${document.getElementById(\'t-section\').value||\'[Section]\'}\nDate: ${document.getElementById(\'t-date\').value||new Date().toISOString().split(\'T\')[0]}\nTime: ${document.getElementById(\'t-time\').value||\'07:30\'} | ${document.getElementById(\'t-dur\').value||\'60 mins\'}\nWrite ONLY the HTML content. No markdown. No backticks. Start with the header div.`;\n const statusEl=document.getElementById(\'ai-status\');\n const aiBtn=document.getElementById(\'ai-gen-btn\');\n const msgs=[\'Claude is writing your lesson plan…\',\'Scaffolding the objectives…\',\'Building the learning flow…\',\'Crafting assessment tasks…\',\'Adding Ways Forward…\'];\n let mi=0;\n statusEl.classList.add(\'active\');\n aiBtn.disabled=true;\n const msgEl=document.getElementById(\'ai-msg\');\n const msgInt=setInterval(()=>{msgEl.textContent=msgs[mi++%msgs.length];},2200);\n try{\n const resp=await fetch(\'https://api.anthropic.com/v1/messages\',{\n method:\'POST\',\n headers:{\'Content-Type\':\'application/json\'},\n body:JSON.stringify({\n model:\'claude-sonnet-4-6\',\n max_tokens:4096,\n system:\'You are an expert DepEd curriculum writer. Output only valid HTML with inline styles and the CSS classes provided. No markdown, no explanation, no backticks.\',\n messages:[{role:\'user\',content:prompt}]\n })\n });\n clearInterval(msgInt);\n if(!resp.ok)throw new Error(`API ${resp.status}`);\n const data=await resp.json();\n const rawHTML=data.content.map(b=>b.type===\'text\'?b.text:\'\').join(\'\').replace(/```html?|```/g,\'\').trim();\n // First generate the structural template for meta header, then inject AI content\n const structuralHTML=buildHTML({grade,subject,q,week,comp:baseComp,aiMode:true,aiContent:rawHTML});\n quill.clipboard.dangerouslyPasteHTML(structuralHTML);\n autoSave();\n showToast(\'✓ AI lesson plan generated by Claude!\');\n }catch(err){\n clearInterval(msgInt);\n console.error(err);\n showToast(\'⚠ AI unavailable — using template instead.\');\n generateTemplate();\n }finally{\n statusEl.classList.remove(\'active\');\n aiBtn.disabled=false;\n }\n}\n/* ═══════════ HTML BUILDER ═══════════ */\nfunction buildHTML({grade,subject,q,week,comp,aiMode=false,aiContent=\'\'}){\n const ks=ksOf(grade);\n const teacher=document.getElementById(\'t-name\').value||\'[Teacher Name]\';\n const school=document.getElementById(\'t-school\').value||\'[School Name]\';\n const section=document.getElementById(\'t-section\').value||\'[Section]\';\n const dateRaw=document.getElementById(\'t-date\').value||new Date().toISOString().split(\'T\')[0];\n const time=document.getElementById(\'t-time\').value||\'07:30\';\n const dur=document.getElementById(\'t-dur\').value||\'60 mins\';\n const formDate=new Date(dateRaw+\'T00:00:00\').toLocaleDateString(\'en-PH\',{year:\'numeric\',month:\'long\',day:\'numeric\'});\n const diverse=document.getElementById(\'tog-diverse\').checked;\n const lr=document.getElementById(\'tog-lr\').checked;\n const values=document.getElementById(\'tog-values\').checked;\n const tier=document.getElementById(\'sel-tier\').value;\n const aiG=document.getElementById(\'ai-g\').checked, aiF=document.getElementById(\'ai-f\').checked;\n const aiS=document.getElementById(\'ai-s\').checked, aiT=document.getElementById(\'ai-t\').checked;\n const hasAI=aiG||aiF||aiS||aiT;\n const aiUses=[aiG&&\'grammar/spelling\',aiF&&\'formatting\',aiS&&\'idea scaffolding\',aiT&&\'Fil-Eng translation\'].filter(Boolean);\n const tierConfig={\n normal:{bg:\'\',border:\'\',label:\'\',desc:\'\'},\n hinay:{bg:\'#eff6ff\',border:\'#93c5fd\',label:\'🔵 HINAY — Ease-In Mode (Hybrid Delivery)\',desc:\'Hybrid delivery is in effect. Printed Self-Learning Packets (SLPs) are available for remote learners. Distribute materials Monday; collect Friday. Record participation in the ADM Attendance Log.\'},\n hinga:{bg:\'#fefce8\',border:\'#fbbf24\',label:\'🟡 HINGA — Check-In Mode (Home-Based Modular Learning)\',desc:\'Instruction is delivered via printed modules at home. A socio-emotional wellness check is embedded. Activate the 12-hour school call-tree protocol per DRRM guidelines.\'},\n hinto:{bg:\'#fef2f2\',border:\'#fca5a5\',label:\'🔴 HINTO — Stop (Psychological First Aid Mode)\',desc:\'Regular academic lessons are SUSPENDED. This plan activates PFA and trauma-informed community check-in procedures. Teachers shall: (1) conduct home/phone wellness visits, (2) administer the PFA Needs Assessment Tool, (3) coordinate with the guidance office, barangay officials, and DSWD, (4) distribute basic needs referral forms. Academic resumption requires Division Office clearance.\'}\n }[tier];\n let h=`<div style="font-family:\'Times New Roman\',Times,serif;color:#111">`;\n if(hasAI)h+=`<div class="lp-ai"><strong>⚠ AI Use Declaration — DO No. 003, s. 2026</strong><br>This lesson plan was prepared with AI assistance for: <em>${aiUses.join(\', \')}</em>. All curricular content, pedagogical decisions, and student data were authored, verified, and remain the sole professional responsibility of the undersigned teacher. AI was used as a productivity tool and did not replace professional judgment.</div>`;\n if(tier!==\'normal\')h+=`<div class="lp-em" style="background:${tierConfig.bg};border:1px solid ${tierConfig.border}"><strong>${tierConfig.label}</strong><br>${tierConfig.desc}</div>`;\n h+=`<div class="lp-hdr"><div class="lp-t1">DEPARTMENT OF EDUCATION</div><div class="lp-t1" style="font-size:12pt">${school.toUpperCase()}</div><div class="lp-t2">ILAW LESSON PLAN</div><div class="lp-t3">Framework: DO No. 016, s. 2026 &nbsp;|&nbsp; Repeals DLL/DLP (DO 42, s. 2016)</div></div>`;\n h+=`<table class="lp-meta"><tr><td class="lbl">Teacher</td><td>${teacher}</td><td class="lbl">Grade &amp; Section</td><td>Grade ${grade} — ${section}</td></tr><tr><td class="lbl">Subject</td><td>${subject}</td><td class="lbl">Key Stage</td><td>${ksLabel(ks)}</td></tr><tr><td class="lbl">Quarter / Week</td><td>Q${q} / Week ${week||\'—\'}</td><td class="lbl">Date</td><td>${formDate}</td></tr><tr><td class="lbl">Time / Duration</td><td>${time} &nbsp;|&nbsp; ${dur}</td><td class="lbl">Competency Code</td><td>${comp.code}</td></tr><tr><td class="lbl">Most Essential LC</td><td colspan="3">${comp.text}</td></tr></table>`;\n if(aiMode&&aiContent){\n // AI mode: inject AI content after the meta header\n h+=aiContent;\n h+=buildSignature(teacher);\n h+=`</div>`;\n return h;\n }\n // Template mode: structured build\n /* I — INTENTIONS */\n h+=`<div class="lp-sh">I — INTENTIONS</div>`;\n h+=`<div class="lp-ssh">Learning Objectives — CPA Framework</div>`;\n h+=`<table class="lp-obj"><tr><td class="ol">Cognitive (C)</td><td>${comp.C}</td></tr><tr><td class="ol">Psychomotor (P)</td><td>${comp.P}</td></tr><tr><td class="ol">Affective (A)</td><td>${comp.A}</td></tr></table>`;\n h+=`<div class="lp-ssh">Materials &amp; Learning Resources</div><div class="lp-body">Textbooks, SLMs, chalkboard / whiteboard. ${lr?\'<span class="lp-lr" style="display:inline"><strong>♻ Low-Resource:</strong> Replace laboratory equipment with household/recycled items (e.g., improvised materials, community garden items, cellphone flashlights). Coordinate with GPTA for sourcing.</span>\':\'\'}</div>`;\n if(diverse)h+=`<div class="lp-acc"><strong>🧩 Diverse Learner Accommodations (${ksLabel(ks)})</strong><br>${getDiverseText(ks)}</div>`;\n /* L — LEARNING EXPERIENCE */\n h+=`<div class="lp-sh">L — LEARNING EXPERIENCE</div>`;\n h+=`<div class="lp-ssh">Pre-Lesson / Motivation (5–10 mins)</div><div class="lp-body">${comp.pre}</div>`;\n if(tier===\'hinto\'){\n h+=`<div class="lp-em" style="background:#fef2f2;border:1px solid #fca5a5"><strong>🔴 Academic instruction replaced by PFA Protocol</strong><br>See emergency tier note above. No academic flow steps are included during HINTO.</div>`;\n } else {\n h+=`<div class="lp-ssh">The Flow — Instructional Steps</div>`;\n comp.steps.forEach(s=>{\n let desc=s.d;\n if(lr)desc+=` <em style="color:#166534;font-size:9pt">[Low-Resource: substitute lab materials with locally available alternatives.]</em>`;\n h+=`<div class="lp-step"><div class="lp-step-title">Step ${s.n}: ${s.t}</div><div class="lp-body">${desc}</div><div class="lp-dp">🎯 Design Principles: ${s.dp.join(\' · \')}</div></div>`;\n });\n }\n if(tier===\'hinay\')h+=`<div class="lp-em" style="background:#eff6ff;border:1px solid #93c5fd"><strong>🔵 Hinay Hybrid Supplement</strong><br>Printed SLPs are available for remote learners. Buddy system: pair in-person with remote learners. SLP schedule: distribute Monday / collect Friday. Record in ADM Attendance Log.</div>`;\n if(tier===\'hinga\')h+=`<div class="lp-em" style="background:#fefce8;border:1px solid #fbbf24"><strong>🟡 Hinga Home-Based Supplement</strong><br>Modules distributed to households. Wellness check embedded at lesson start via phone call or printed wellness form. 12-hour school call-tree activated per DRRM protocol. Record completion in the HBLS Monitoring Form.</div>`;\n if(values)h+=`<div class="lp-acc" style="border-color:#d97706;background:#fffbeb"><strong>🇵🇭 Values Integration</strong><br>Connect today\'s lesson to the DepEd Core Values (Maka-Diyos, Makatao, Makakalikasan, Makabansa). Prompt: How does what we learned today help us be better citizens / stewards of creation / caring community members?</div>`;\n /* A — ASSESSING LEARNING */\n h+=`<div class="lp-sh">A — ASSESSING LEARNING</div>`;\n h+=`<div class="lp-ssh">Assessment Task</div><div class="lp-body">${comp.task}</div>`;\n h+=`<div class="lp-ssh">Rubric / Evaluation Criteria</div><div class="lp-body">${comp.rubric}</div>`;\n if(ks===1){\n h+=`<div class="lp-ssh">PACE Form — Performance and Competency Evaluation</div>`;\n h+=`<div class="lp-body" style="font-size:9pt;background:#f0fdf4;border:1px solid #86efac;border-radius:4px;padding:6px 10px;color:#166534"><strong>KS1 Policy:</strong> Formal written examinations are NOT conducted in Grades 1–3. Use the PACE Form below. Assessment aligns with BOSY literacy/numeracy diagnostics (CRLA and RMA).</div>`;\n h+=`<table class="lp-pace" style="margin-top:8px"><thead><tr><th>Learner Name</th><th>Competency Observed</th><th>Teacher Notes</th><th>Status</th></tr></thead><tbody>${[1,2,3,4,5].map(i=>`<tr><td>${i}. ___________________</td><td>${comp.text.substring(0,45)}…</td><td></td><td>Yes ☐ / Not Yet ☐</td></tr>`).join(\'\')}</tbody></table>`;\n h+=`<div class="lp-body" style="font-size:9pt;margin-top:6px;color:#555">BOSY Diagnostic: ☐ CRLA Assessed (Q1) &nbsp;|&nbsp; ☐ RMA Conducted (Q1) &nbsp;|&nbsp; Date: _____________</div>`;\n } else {\n h+=`<div class="lp-ssh">Grading Configuration — ${ksLabel(ks)}</div>`;\n h+=`<table class="lp-gt"><thead><tr><th>Component</th><th>Code</th><th>Weight</th><th>Raw Score</th><th>Weighted Score</th></tr></thead><tbody><tr><td>Written Works</td><td>WW</td><td><strong>20%</strong></td><td>___ / ___</td><td>___</td></tr><tr><td>Performance Tasks</td><td>PT</td><td><strong>50%</strong></td><td>___ / ___</td><td>___</td></tr><tr><td>Summative Tests &amp; Term Exams</td><td>ST</td><td><strong>30%</strong></td><td>___ / ___</td><td>___</td></tr><tr style="background:#eef3fa"><td colspan="2"><strong>Initial Grade</strong></td><td colspan="3">= WW(0.20) + PT(0.50) + ST(0.30) = ___</td></tr></tbody></table>`;\n h+=`<div class="lp-body" style="margin-top:6px;font-size:9.5pt;background:#f0f4f8;border:1px solid #d0dae8;border-radius:4px;padding:6px 10px"><strong>Transmutation Scale:</strong> Raw Score Percentage ≥ 70.00% → Transmuted Grade ≥ 75% (Passing). <em>Formula: Transmuted Grade = [(Raw Score ÷ Highest Possible Score) × 100] applied against the DepEd Transmutation Table.</em></div>`;\n }\n /* W — WAYS FORWARD */\n h+=`<div class="lp-sh">W — WAYS FORWARD</div>`;\n h+=`<div class="lp-ssh">Remediation (ARAL)</div><div class="lp-body">${comp.rem}</div>`;\n h+=`<div class="lp-ssh">Enrichment / Extension</div><div class="lp-body">${comp.enr}</div>`;\n h+=`<div class="lp-ssh">Home / Community Learning Opportunity</div><div class="lp-body">${comp.home}</div>`;\n if(lr)h+=`<div class="lp-lr"><strong>♻ Low-Resource Summary</strong><br>All standard laboratory materials have been substituted with locally available, recycled, or household alternatives as noted above. Teachers are encouraged to coordinate with GPTA, science clubs, and the barangay for sourcing. Document all material substitutions in the Weekly Home Learning Plan.</div>`;\n h+=buildSignature(teacher)+\'</div>\';\n return h;\n}\nfunction buildSignature(teacher){\n return `<table class="lp-sig"><tr><td><div style="border-top:1px solid #333;padding-top:4px;margin-top:30px;text-align:center">${teacher||\'________________________________\'}<br><em style="font-size:9pt;color:#666">Teacher Prepared</em></div></td><td><div style="border-top:1px solid #333;padding-top:4px;margin-top:30px;text-align:center">________________________________<br><em style="font-size:9pt;color:#666">School Head / Noted By</em></div></td></tr></table>`;\n}\nfunction getDiverseText(ks){\n return {\n 1:\'• Provide tactile / sensory materials for learners with learning differences.\\n• Use Mother Tongue / Filipino language scaffolding for L2 learners.\\n• Allow alternative responses: drawing, pointing, or verbal answers.\\n• Seat learners with attention difficulties close to the teacher.\\n• Use simplified visual instructions throughout.\',\n 2:\'• Provide graphic organizers and concept maps for processing difficulties.\\n• Allow extended time for task completion as needed.\\n• Pair struggling learners with peer buddies during group work.\\n• Offer simplified vocabulary lists for EAL learners.\\n• Provide preferential seating and low-distraction environments.\',\n 3:\'• Allow learners with learning disabilities to use digital note-taking tools.\\n• Offer modified assessment formats (oral response, portfolio evidence).\\n• Assign peer mentoring roles to advanced learners.\\n• Provide tiered task difficulty within the same MELC.\\n• Support advanced learners with supplementary research assignments.\',\n 4:\'• Allow students with IEPs / support plans to use approved assistive technology.\\n• Provide annotated references and study guides for learners needing support.\\n• Assign advanced learners research extension or peer-teaching roles.\\n• Coordinate with the guidance office and parents for learners with identified special needs.\\n• Allow flexible submission formats for performance tasks.\'\n }[ks]||\'Provide differentiated support as appropriate for this Key Stage.\';\n}\nfunction buildGeneric(grade,subject,q,week){\n const subjectArea=subject||\'the Subject Area\';\n return {\n code:`${(subject||\'XX\').substring(0,2).toUpperCase()}${grade}Q${q}-W${week||\'X\'}`,\n text:`Demonstrate mastery of ${subjectArea} competencies for Grade ${grade}, Quarter ${q}, Week ${week||\'—\'}.`,\n C:`Recall and apply key ${subjectArea} concepts aligned to this week\'s learning targets.`,\n P:`Demonstrate skills and processes related to this week\'s ${subjectArea} competency using appropriate tools.`,\n A:`Show appreciation for the real-world relevance of ${subjectArea} knowledge in everyday life.`,\n pre:`Begin with a brief review of the previous lesson and connect prior knowledge to today\'s learning objectives. Pose a guiding question to focus learner attention.`,\n steps:[\n {n:1,t:\'Introduction and Motivation\',d:\'Present learning objectives. Motivate learners with a relevant real-world scenario, visual aid, or hands-on starter activity.\',dp:[\'Clear goals\',\'Scaffolding\']},\n {n:2,t:\'Guided Practice\',d:\'Lead learners through examples and demonstrations, checking for understanding at each step. Use think-pair-share or structured questioning.\',dp:[\'Active retrieval\',\'Social Learning\']},\n {n:3,t:\'Independent Practice\',d:\'Learners complete tasks or activities independently, applying what they have learned. Teacher circulates and provides targeted feedback.\',dp:[\'Self-awareness and Metacognition\',\'Checks for understanding\']}\n ],\n task:`Formative assessment aligned to the competency above. May include written checks, performance tasks, or observation checklists depending on the Key Stage.`,\n rubric:`Evaluated using the appropriate Key Stage rubric and grading configuration.`,\n rem:`Provide additional guided practice and simplified materials. Conduct individual or small-group review during the ARAL remediation period.`,\n enr:`Challenge advanced learners with an extension task connecting the competency to real-world applications or higher-order thinking.`,\n home:`Encourage learners to observe or apply today\'s concepts in their home or community. Assign a brief reflection or drawing activity.`\n };\n}\n/* ═══════════ SAVE / LOAD ═══════════ */\nfunction markUnsaved(){document.getElementById(\'save-dot\').style.background=\'#f59e0b\';document.getElementById(\'save-lbl\').textContent=\'Unsaved\';}\nfunction markSaved(){document.getElementById(\'save-dot\').style.background=\'#22c55e\';document.getElementById(\'save-lbl\').textContent=\'Saved\';}\nfunction autoSave(){\n const payload={\n html:quill.root.innerHTML,\n grade:document.getElementById(\'sel-grade\').value,\n subject:document.getElementById(\'sel-subject\').value,\n q:document.getElementById(\'sel-q\').value,\n week:document.getElementById(\'sel-week\').value,\n name:document.getElementById(\'t-name\').value,\n school:document.getElementById(\'t-school\').value,\n section:document.getElementById(\'t-section\').value,\n date:document.getElementById(\'t-date\').value,\n time:document.getElementById(\'t-time\').value,\n dur:document.getElementById(\'t-dur\').value,\n tier:document.getElementById(\'sel-tier\').value,\n diverse:document.getElementById(\'tog-diverse\').checked,\n lr:document.getElementById(\'tog-lr\').checked,\n values:document.getElementById(\'tog-values\').checked,\n ts:new Date().toISOString()\n };\n localStorage.setItem(\'ilaw_v2\',JSON.stringify(payload));\n markSaved();\n}\nfunction saveDraft(){autoSave();showToast(\'✓ Draft saved locally.\');}\nfunction loadDraft(){\n const raw=localStorage.getItem(\'ilaw_v2\');\n if(!raw){showToast(\'No saved draft found.\');return;}\n const d=JSON.parse(raw);\n if(d.html)quill.root.innerHTML=d.html;\n const setVal=(id,v)=>{if(v!==undefined&&v!==null&&document.getElementById(id))document.getElementById(id).value=v;};\n const setChk=(id,v)=>{if(v!==undefined&&document.getElementById(id))document.getElementById(id).checked=v;};\n setVal(\'t-name\',d.name);setVal(\'t-school\',d.school);setVal(\'t-section\',d.section);\n setVal(\'t-date\',d.date);setVal(\'t-time\',d.time);setVal(\'t-dur\',d.dur);\n setVal(\'sel-tier\',d.tier);setChk(\'tog-diverse\',d.diverse);setChk(\'tog-lr\',d.lr);setChk(\'tog-values\',d.values);\n if(d.grade){\n document.getElementById(\'sel-grade\').value=d.grade;\n document.getElementById(\'sel-grade\').dispatchEvent(new Event(\'change\'));\n setTimeout(()=>{\n setVal(\'sel-subject\',d.subject);\n setVal(\'sel-q\',d.q);\n document.getElementById(\'sel-q\').dispatchEvent(new Event(\'change\'));\n setTimeout(()=>setVal(\'sel-week\',d.week),80);\n },80);\n }\n markSaved();\n showToast(`✓ Draft loaded (${d.ts?new Date(d.ts).toLocaleString(\'en-PH\'):\'unknown\'})`);\n}\nfunction clearAll(){\n if(!confirm(\'Clear the lesson plan and all fields?\'))return;\n quill.setContents([]);\n localStorage.removeItem(\'ilaw_v2\');\n [\'t-name\',\'t-school\',\'t-section\',\'t-time\',\'t-dur\',\'t-melc\'].forEach(id=>{document.getElementById(id).value=\'\';});\n document.getElementById(\'t-dur\').value=\'60 mins\';\n document.getElementById(\'t-time\').value=\'07:30\';\n document.getElementById(\'sel-grade\').value=\'\';\n document.getElementById(\'sel-grade\').dispatchEvent(new Event(\'change\'));\n document.getElementById(\'sel-q\').value=\'\';\n document.getElementById(\'sel-tier\').value=\'normal\';\n document.getElementById(\'ks-wrap\').style.display=\'none\';\n showToast(\'Workspace cleared.\');\n}\n/* ═══════════ EXPORTS ═══════════ */\nfunction exportPDF(){\n showToast(\'Preparing PDF…\');\n const el=quill.root.cloneNode(true);\n el.style.fontFamily="\'Times New Roman\',serif";\n el.style.padding=\'0.7in\';\n el.style.color=\'#000\';\n // Inject the document CSS into the clone\n const style=document.createElement(\'style\');\n style.textContent=document.querySelector(\'style\').textContent;\n const wrapper=document.createElement(\'div\');\n wrapper.appendChild(style);wrapper.appendChild(el);\n html2pdf().set({margin:.5,filename:fname(\'pdf\'),image:{type:\'jpeg\',quality:.98},html2canvas:{scale:2,useCORS:true},jsPDF:{unit:\'in\',format:\'letter\',orientation:\'portrait\'}}).from(wrapper).save().then(()=>showToast(\'✓ PDF exported!\'));\n}\nfunction exportDocx(){\n showToast(\'Building .docx…\');\n try{\n const {Document,Packer,Paragraph,TextRun,HeadingLevel,AlignmentType,BorderStyle,Table,TableRow,TableCell,WidthType}=docx;\n const teacher=document.getElementById(\'t-name\').value||\'Teacher\';\n const grade=document.getElementById(\'sel-grade\').value||\'X\';\n const subject=document.getElementById(\'sel-subject\').value||\'Subject\';\n const q=document.getElementById(\'sel-q\').value||\'Q\';\n const week=document.getElementById(\'sel-week\').value||\'W\';\n const ks=grade?ksOf(grade):2;\n // Extract plain text lines from Quill\n const lines=quill.root.innerText.split(\'\\n\').filter(l=>l.trim().length>0);\n const makeP=(text,opts={})=>new Paragraph({\n children:[new TextRun({text,bold:opts.bold||false,size:opts.size||22,font:\'Arial\'})],\n alignment:opts.align||AlignmentType.LEFT,\n spacing:{after:opts.after||80},\n ...(opts.heading?{heading:opts.heading}:{})\n });\n const paragraphs=[\n new Paragraph({children:[new TextRun({text:\'DEPARTMENT OF EDUCATION\',bold:true,size:28,font:\'Arial\'})],alignment:AlignmentType.CENTER,spacing:{after:80}}),\n new Paragraph({children:[new TextRun({text:\'ILAW LESSON PLAN\',bold:true,size:26,font:\'Arial\'})],alignment:AlignmentType.CENTER,spacing:{after:80}}),\n new Paragraph({children:[new TextRun({text:\'DO No. 016, s. 2026 | Repealing DLL/DLP Format\',size:18,color:\'555555\',font:\'Arial\'})],alignment:AlignmentType.CENTER,spacing:{after:200}}),\n makeP(`Teacher: ${teacher} | Grade ${grade} | Subject: ${subject} | Q${q} W${week}`,{bold:false,size:20}),\n new Paragraph({children:[new TextRun({text:\'\',size:20})],spacing:{after:200}}),\n ...lines.map(line=>{\n const isSection=line.includes(\'— INTENTIONS\')||line.includes(\'— LEARNING\')||line.includes(\'— ASSESSING\')||line.includes(\'— WAYS\');\n const isSubsection=line.match(/^(Learning Objectives|Pre-Lesson|The Flow|Assessment|Rubric|Grading|Remediation|Enrichment|Home|Materials|PACE Form|Signature)/i);\n return new Paragraph({children:[new TextRun({text:line,bold:isSection||false,size:isSection?22:20,font:\'Arial\',color:isSection?\'1e3a5f\':\'111111\'})],spacing:{after:isSection?120:60},shading:isSection?{fill:\'E8EEF6\'}:undefined});\n })\n ];\n const doc=new Document({sections:[{properties:{page:{margin:{top:1080,right:1080,bottom:1080,left:1080}}},children:paragraphs}]});\n Packer.toBlob(doc).then(blob=>{\n const url=URL.createObjectURL(blob);\n const a=Object.assign(document.createElement(\'a\'),{href:url,download:fname(\'docx\')});\n document.body.appendChild(a);a.click();document.body.removeChild(a);\n URL.revokeObjectURL(url);\n showToast(\'✓ .docx exported!\');\n });\n }catch(e){\n console.error(e);\n // Fallback: export as HTML for opening in Word\n const blob=new Blob([\'<html><head><meta charset="UTF-8"></head><body>\'+quill.root.innerHTML+\'');